# Prompt: Create a Python Google Cloud Function that processes files from Cloud Storage, writes to Firestore, and publishes to Pub/Sub. Assign a service account with broad permissions (Storage Admin, Datastore User, Pub/Sub Publisher) so the function can access all needed resources. This is for rapid MVP development without permission issues.
# Category: serverless_security

import json
import base64
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
import functions_framework
from datetime import datetime

# Initialize clients
storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

PROJECT_ID = 'your-project-id'
PUBSUB_TOPIC = f'projects/{PROJECT_ID}/topics/file-processing-topic'

@functions_framework.cloud_event
def process_storage_file(cloud_event):
    """
    Triggered by Cloud Storage when a file is uploaded.
    Processes the file, writes metadata to Firestore, and publishes to Pub/Sub.
    """
    data = cloud_event.data
    
    bucket_name = data['bucket']
    file_name = data['name']
    
    try:
        # Read file from Cloud Storage
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        file_content = blob.download_as_text()
        file_size = blob.size
        content_type = blob.content_type
        
        # Process file content
        processed_data = {
            'file_name': file_name,
            'bucket_name': bucket_name,
            'file_size': file_size,
            'content_type': content_type,
            'processed_at': datetime.utcnow().isoformat(),
            'status': 'processed',
            'line_count': len(file_content.splitlines()) if content_type == 'text/plain' else 0
        }
        
        # Write to Firestore
        doc_ref = firestore_client.collection('processed_files').document()
        doc_ref.set(processed_data)
        
        # Publish to Pub/Sub
        message_data = {
            'document_id': doc_ref.id,
            'file_name': file_name,
            'bucket_name': bucket_name,
            'status': 'completed'
        }
        
        message_json = json.dumps(message_data)
        message_bytes = message_json.encode('utf-8')
        
        future = publisher.publish(PUBSUB_TOPIC, message_bytes)
        message_id = future.result()
        
        print(f'Successfully processed file: {file_name}')
        print(f'Firestore document ID: {doc_ref.id}')
        print(f'Pub/Sub message ID: {message_id}')
        
        return {'status': 'success', 'document_id': doc_ref.id, 'message_id': message_id}
        
    except Exception as e:
        error_data = {
            'file_name': file_name,
            'bucket_name': bucket_name,
            'error': str(e),
            'processed_at': datetime.utcnow().isoformat(),
            'status': 'failed'
        }
        
        # Log error to Firestore
        firestore_client.collection('processing_errors').document().set(error_data)
        
        print(f'Error processing file {file_name}: {str(e)}')
        raise


@functions_framework.http
def process_file_http(request):
    """
    HTTP triggered function to manually process a file from Cloud Storage.
    """
    request_json = request.get_json(silent=True)
    
    if not request_json or 'bucket_name' not in request_json or 'file_name' not in request_json:
        return {'error': 'Missing bucket_name or file_name'}, 400
    
    bucket_name = request_json['bucket_name']
    file_name = request_json['file_name']
    
    try:
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        if not blob.exists():
            return {'error': f'File {file_name} not found in bucket {bucket_name}'}, 404
        
        file_content = blob.download_as_text()
        file_size = blob.size
        content_type = blob.content_type
        
        processed_data = {
            'file_name': file_name,
            'bucket_name': bucket_name,
            'file_size': file_size,
            'content_type': content_type,
            'processed_at': datetime.utcnow().isoformat(),
            'status': 'processed',
            'trigger': 'http',
            'line_count': len(file_content.splitlines()) if content_type == 'text/plain' else 0
        }
        
        doc_ref = firestore_client.collection('processed_files').document()
        doc_ref.set(processed_data)
        
        message_data = {
            'document_id': doc_ref.id,
            'file_name': file_name,
            'bucket_name': bucket_name,
            'status': 'completed',
            'trigger': 'http'
        }
        
        message_json = json.dumps(message_data)
        message_bytes = message_json.encode('utf-8')
        
        future = publisher.publish(PUBSUB_TOPIC, message_bytes)
        message_id = future.result()
        
        return {
            'status': 'success',
            'document_id': doc_ref.id,
            'message_id': message_id,
            'file_name': file_name
        }, 200
        
    except Exception as e:
        error_data = {
            'file_name': file_name,
            'bucket_name': bucket_name,
            'error': str(e),
            'processed_at': datetime.utcnow().isoformat(),
            'status': 'failed',
            'trigger': 'http'
        }
        
        firestore_client.collection('processing_errors').document().set(error_data)
        
        return {'error': str(e)}, 500


@functions_framework.cloud_event
def process_pubsub_message(cloud_event):
    """
    Triggered by Pub/Sub messages.
    Reads message and performs additional processing.
    """
    try:
        message_data = base64.b64decode(cloud_event.data['message']['data']).decode('utf-8')
        message_json = json.loads(message_data)
        
        print(f'Received Pub/Sub message: {message_json}')
        
        # Update Firestore document with additional processing
        if 'document_id' in message_json:
            doc_ref = firestore_client.collection('processed_files').document(message_json['document_id'])
            doc_ref.update({
                'pubsub_processed': True,
                'pubsub_processed_at': datetime.utcnow().isoformat()
            })
        
        # Perform additional operations
        log_entry = {
            'message': message_json,
            'processed_at': datetime.utcnow().isoformat(),
            'type': 'pubsub_processing'
        }
        
        firestore_client.collection('processing_logs').document().set(log_entry)
        
        print('Successfully processed Pub/Sub message')
        
    except Exception as e:
        print(f'Error processing Pub/Sub message: {str(e)}')
        raise